import { Link } from 'react-router-dom';
import { ArrowRight, Globe, Gamepad2, Palette, CheckCircle, ChevronRight } from 'lucide-react';
import { useEffect, useRef, useState } from 'react';

function Counter({ end, suffix='' }) {
  const [v,setV]=useState(0); const ref=useRef(null); const started=useRef(false);
  useEffect(()=>{
    const io=new IntersectionObserver(([e])=>{
      if(e.isIntersecting&&!started.current){
        started.current=true; let c=0; const step=end/48;
        const t=setInterval(()=>{c+=step;if(c>=end){setV(end);clearInterval(t)}else setV(Math.floor(c))},28);
      }
    },{threshold:0.4});
    if(ref.current)io.observe(ref.current);
    return()=>io.disconnect();
  },[end]);
  return <span ref={ref}>{v}{suffix}</span>;
}

const SERVICES=[
  {id:'fullstack',Icon:Globe,   title:'Full Stack Development',desc:'End-to-end web solutions from pixel-perfect frontends to powerful, scalable backends.',img:'https://images.unsplash.com/photo-1461749280684-dccba630e2f6?w=700&q=80'},
  {id:'gamedev', Icon:Gamepad2, title:'Game Development',      desc:'2D & 3D games, mobile titles, and immersive interactive experiences that engage players.',img:'https://images.unsplash.com/photo-1593305841991-05c297ba4575?w=700&q=80'},
  {id:'uiux',    Icon:Palette,  title:'UI/UX Design',          desc:'Interfaces that are intuitive, beautiful and conversion-focused — designed for real users.',img:'https://images.unsplash.com/photo-1561070791-2526d30994b5?w=700&q=80'},
];
const WHY=['Agile development with milestone tracking','Cross-functional teams: dev, design & QA','Scalable cloud-ready architectures','Full NDA protection and client IP ownership','Post-launch support and optimisation'];
const STACK=['React','Node.js','Unity','Unreal','AWS','Azure','Next.js','Docker'];

export default function Home(){return(
  <div>

    {/* HERO */}
    <section style={{position:'relative',minHeight:'100vh',display:'flex',alignItems:'center',justifyContent:'center',background:'#040b18',overflow:'hidden'}}>
      {/* Background image */}
      <img src="https://images.unsplash.com/photo-1519389950473-47ba0277781c?w=1800&q=75" alt="" aria-hidden
        style={{position:'absolute',inset:0,width:'100%',height:'100%',objectFit:'cover',opacity:.12}}/>
      {/* Gradient overlay */}
      <div style={{position:'absolute',inset:0,background:'linear-gradient(160deg,rgba(4,11,24,0.97) 0%,rgba(0,30,90,0.82) 50%,rgba(4,11,24,0.97) 100%)'}}/>
      {/* Subtle glow spot */}
      <div style={{position:'absolute',top:'30%',left:'50%',transform:'translate(-50%,-50%)',width:600,height:600,background:'radial-gradient(circle,rgba(0,87,255,0.1) 0%,transparent 70%)',pointerEvents:'none'}}/>
      {/* Decorative rings */}
      <div className="hide-mobile" style={{position:'absolute',top:'50%',right:-120,transform:'translateY(-50%)',width:500,height:500,border:'1px solid rgba(255,255,255,0.04)',borderRadius:'50%',pointerEvents:'none'}}/>
      <div className="hide-mobile" style={{position:'absolute',top:'50%',right:40,transform:'translateY(-50%)',width:260,height:260,border:'1px solid rgba(0,87,255,0.1)',borderRadius:'50%',pointerEvents:'none'}}/>

      <div className="wrap" style={{position:'relative',zIndex:1,padding:'130px 20px 100px',textAlign:'center',display:'flex',flexDirection:'column',alignItems:'center'}}>

        {/* Live badge */}
        <div className="anim" style={{display:'inline-flex',alignItems:'center',gap:8,padding:'7px 18px',background:'rgba(255,255,255,0.06)',border:'1px solid rgba(255,255,255,0.1)',borderRadius:999,fontSize:'0.76rem',fontWeight:600,color:'rgba(255,255,255,0.7)',marginBottom:32,backdropFilter:'blur(8px)'}}>
          <span style={{width:7,height:7,borderRadius:'50%',background:'#4ade80',boxShadow:'0 0 8px #4ade80',display:'inline-block'}}/>
          Full Stack &amp; Game Development Studio
        </div>

        {/* Headline */}
        <h1 className="t-hero white anim d1" style={{marginBottom:24,maxWidth:820,lineHeight:1.07}}>
          We Build,{' '}
          <em className="italic" style={{color:'#5aa8ff'}}>You Grow.</em>
        </h1>

        {/* Subtext */}
        <p className="anim d2" style={{fontSize:'clamp(0.95rem,1.8vw,1.12rem)',color:'rgba(255,255,255,0.62)',maxWidth:580,lineHeight:1.85,marginBottom:44}}>
          Synnoviq Technologies delivers scalable Full Stack applications and immersive Game Development experiences — engineered with precision, driven by innovation.
        </p>

        {/* CTA Buttons */}
        <div className="anim d3" style={{display:'flex',gap:14,flexWrap:'wrap',justifyContent:'center',marginBottom:56}}>
          <Link to="/services" className="btn btn-blue btn-lg" style={{minWidth:160,justifyContent:'center'}}>
            Explore Services <ArrowRight size={16}/>
          </Link>
          <Link to="/contact" className="btn btn-ghost btn-lg" style={{minWidth:140,justifyContent:'center'}}>
            Let's Talk
          </Link>
        </div>

        {/* Divider */}
        <div className="anim d3" style={{width:40,height:1,background:'rgba(255,255,255,0.15)',marginBottom:28}}/>

        {/* Stack pills */}
        <div className="anim d3" style={{display:'flex',flexWrap:'wrap',gap:8,alignItems:'center',justifyContent:'center'}}>
          <span style={{fontSize:'0.7rem',color:'rgba(255,255,255,0.3)',fontWeight:500,marginRight:4,textTransform:'uppercase',letterSpacing:'0.1em'}}>Our Stack</span>
          {STACK.map(t=>(
            <span key={t} style={{padding:'5px 13px',background:'rgba(255,255,255,0.05)',border:'1px solid rgba(255,255,255,0.1)',borderRadius:999,fontSize:'0.74rem',color:'rgba(255,255,255,0.6)',fontWeight:500,letterSpacing:'0.02em'}}>
              {t}
            </span>
          ))}
        </div>

      </div>

      {/* Scroll indicator */}
      <div style={{position:'absolute',bottom:32,left:'50%',transform:'translateX(-50%)',display:'flex',flexDirection:'column',alignItems:'center',gap:6,opacity:0.35}}>
        <span style={{fontSize:'0.65rem',color:'#fff',letterSpacing:'0.15em',textTransform:'uppercase'}}>Scroll</span>
        <div style={{width:1,height:28,background:'linear-gradient(to bottom,#fff,transparent)'}}/>
      </div>
    </section>

    {/* STATS */}
    <section style={{background:'var(--surf)',borderBottom:'1px solid var(--rule)'}}>
      <div className="wrap">
        <div className="stats-row" style={{borderTop:'1px solid var(--rule)'}}>
          {[{end:50,suf:'+',lbl:'Projects Delivered'},{end:15,suf:'+',lbl:'Technologies'},{end:100,suf:'%',lbl:'Client Satisfaction'}].map(({end,suf,lbl},i)=>(
            <div key={lbl} style={{padding:'44px 24px',textAlign:'center',borderRight:i<2?'1px solid var(--rule)':'none'}}>
              <div className="stat-num"><Counter end={end} suffix={suf}/></div>
              <p style={{fontSize:'0.8rem',color:'var(--ink40)',fontWeight:500,letterSpacing:'0.06em',textTransform:'uppercase',marginTop:6}}>{lbl}</p>
            </div>
          ))}
        </div>
      </div>
    </section>

    {/* WHO WE ARE */}
    <section className="sec">
      <div className="wrap">
        <div className="g2">
          <div>
            <span className="label">Who We Are</span>
            <h2 className="t-h2" style={{marginBottom:20}}>Where Full Stack Meets <em className="italic">Full Imagination</em></h2>
            <p className="t-lg" style={{marginBottom:16}}>Synnoviq Technologies is a forward-thinking software company specializing in Full Stack Development and Game Development.</p>
            <p className="t-md" style={{marginBottom:32}}>From enterprise-grade web platforms to immersive interactive experiences, we bring ideas to life through clean code, creative design and cutting-edge technology.</p>
            <Link to="/about" style={{display:'inline-flex',alignItems:'center',gap:8,color:'var(--blue)',fontWeight:600,fontSize:'0.9rem',transition:'gap 0.2s'}}
              onMouseEnter={e=>e.currentTarget.style.gap='13px'}
              onMouseLeave={e=>e.currentTarget.style.gap='8px'}
            >Learn about us <ArrowRight size={15}/></Link>
          </div>
          {/* IMAGE — simple, no absolute positioning */}
          <div style={{position:'relative'}}>
            <img src="https://images.unsplash.com/photo-1522071820081-009f0129c71c?w=800&q=80" alt="Team collaborating" style={{width:'100%',height:360,objectFit:'cover',borderRadius:'var(--r4)',boxShadow:'var(--sh3)'}}/>
            {/* floating badge */}
            <div style={{position:'absolute',bottom:20,left:20,background:'rgba(255,255,255,0.97)',backdropFilter:'blur(12px)',borderRadius:'var(--r3)',padding:'12px 16px',boxShadow:'var(--sh2)',border:'1px solid var(--rule)',display:'flex',alignItems:'center',gap:10}}>
              <div style={{width:36,height:36,borderRadius:8,background:'var(--blue-s)',border:'1px solid var(--blue-t)',display:'flex',alignItems:'center',justifyContent:'center',color:'var(--blue)',fontSize:'1.1rem',fontWeight:800}}>✓</div>
              <div>
                <div style={{fontWeight:700,fontSize:'0.86rem',color:'var(--ink)',lineHeight:1.2}}>100% Satisfaction</div>
                <div style={{fontSize:'0.7rem',color:'var(--ink40)'}}>Across all projects</div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>

    {/* SERVICES */}
    <section className="sec" style={{background:'var(--surf)',borderTop:'1px solid var(--rule)',borderBottom:'1px solid var(--rule)'}}>
      <div className="wrap">
        <div className="sh-c">
          <span className="label">What We Do</span>
          <h2 className="t-h2">Our Core Services</h2>
        </div>
        <div className="g3">
          {SERVICES.map(({id,Icon,title,desc,img})=>(
            <Link key={id} to={`/services#${id}`} style={{textDecoration:'none',display:'block'}}>
              <div className="card" style={{height:'100%',display:'flex',flexDirection:'column'}}
                onMouseEnter={e=>{e.currentTarget.style.borderColor='var(--blue)';e.currentTarget.style.boxShadow='var(--sh2)';e.currentTarget.style.transform='translateY(-4px)'}}
                onMouseLeave={e=>{e.currentTarget.style.borderColor='var(--rule)';e.currentTarget.style.boxShadow='none';e.currentTarget.style.transform='translateY(0)'}}
              >
                <div style={{height:200,overflow:'hidden',position:'relative'}}>
                  <img src={img} alt={title} style={{width:'100%',height:'100%',objectFit:'cover',transition:'transform 0.4s ease'}}
                    onMouseEnter={e=>e.currentTarget.style.transform='scale(1.06)'}
                    onMouseLeave={e=>e.currentTarget.style.transform='scale(1)'}
                  />
                  <div style={{position:'absolute',inset:0,background:'linear-gradient(to bottom,transparent 50%,rgba(0,0,0,0.3))'}}/>
                </div>
                <div style={{padding:'24px',flex:1,display:'flex',flexDirection:'column'}}>
                  <div style={{width:42,height:42,borderRadius:10,background:'var(--blue-s)',border:'1px solid var(--blue-t)',display:'flex',alignItems:'center',justifyContent:'center',color:'var(--blue)',marginBottom:14}}>
                    <Icon size={19}/>
                  </div>
                  <h3 className="t-h3" style={{marginBottom:8}}>{title}</h3>
                  <p className="t-sm" style={{flex:1,marginBottom:16}}>{desc}</p>
                  <span style={{display:'flex',alignItems:'center',gap:5,fontSize:'0.8rem',fontWeight:700,color:'var(--blue)'}}>Learn more<ChevronRight size={13}/></span>
                </div>
              </div>
            </Link>
          ))}
        </div>
      </div>
    </section>

    {/* WHY SYNNOVIQ */}
    <section className="sec">
      <div className="wrap">
        <div className="g2">
          {/* Image with overlay card */}
          <div style={{position:'relative',borderRadius:'var(--r4)',overflow:'hidden',minHeight:380}}>
            <img src="https://images.unsplash.com/photo-1553877522-43269d4ea984?w=900&q=80" alt="Office and technology" style={{width:'100%',height:'100%',objectFit:'cover',position:'absolute',inset:0}}/>
